1608	func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) (err error) {
1609		start := time.Now()
1610		timingsLogger := logger
1611		logger.Info("Loading configuration file", "filename", filename)
1612	
1613		defer func() {
1614			if err == nil {
1615				configSuccess.Set(1)
1616				configSuccessTime.SetToCurrentTime()
1617				callback(true)
1618			} else {
1619				configSuccess.Set(0)
1620				callback(false)
1621			}
1622		}()
1623	
1624		conf, err := config.LoadFile(filename, agentMode, logger)
1625		if err != nil {
1626			return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
1627		}
1628	
1629		if enableExemplarStorage {
1630			if conf.StorageConfig.ExemplarsConfig == nil {
1631				conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
1632			}
1633		}
1634	
1635		failed := false
1636		for _, rl := range rls {
1637			rstart := time.Now()
1638			if err := rl.reloader(conf); err != nil {
1639				logger.Error("Failed to apply configuration", "err", err)
1640				failed = true
1641			}
1642			timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
1643		}
1644		if failed {
1645			return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
1646		}
1647	
1648		updateGoGC(conf, logger)
1649		noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
1650		timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
1651		return nil
1652	}
