1681	// computeExternalURL computes a sanitized external URL from a raw input. It infers unset
1682	// URL parts from the OS and the given listen address.
1683	func computeExternalURL(u, listenAddr string) (*url.URL, error) {
1684		if u == "" {
1685			hostname, err := os.Hostname()
1686			if err != nil {
1687				return nil, err
1688			}
1689			_, port, err := net.SplitHostPort(listenAddr)
1690			if err != nil {
1691				return nil, err
1692			}
1693			u = fmt.Sprintf("http://%s:%s/", hostname, port)
1694		}
1695	
1696		if startsOrEndsWithQuote(u) {
1697			return nil, errors.New("URL must not begin or end with quotes")
1698		}
1699	
1700		eu, err := url.Parse(u)
1701		if err != nil {
1702			return nil, err
1703		}
1704	
1705		ppref := strings.TrimRight(eu.Path, "/")
1706		if ppref != "" && !strings.HasPrefix(ppref, "/") {
1707			ppref = "/" + ppref
1708		}
1709		eu.Path = ppref
1710	
1711		return eu, nil
1712	}
