// Package reloadstatus tracks and persists the outcome of the most recent
// configuration reload attempt, so it can be inspected over HTTP and
// remains available for diagnosis after a restart.
package reloadstatus

import (
	"encoding/json"
	"errors"
	"log/slog"
	"os"
	"path/filepath"
	"sync"
)

// Error categories for a reload attempt.
const (
	ErrorCategoryNone           = "none"
	ErrorCategoryLoadError      = "load_error"
	ErrorCategoryApplyError     = "apply_error"
	ErrorCategoryRollbackError  = "rollback_error"
	persistedStatusFileBaseName = "reload_status.json"
)

// Status describes the outcome of the most recent configuration reload attempt.
type Status struct {
	LastReloadID         string           `json:"last_reload_id"`
	LastReloadSuccessful bool             `json:"last_reload_successful"`
	ErrorCategory        string           `json:"error_category"`
	ErrorMessage         string           `json:"error_message"`
	AppliedReloaders     []string         `json:"applied_reloaders"`
	RollbackAttempted    bool             `json:"rollback_attempted"`
	RollbackSuccessful   bool             `json:"rollback_successful"`
	FailedReloader       string           `json:"failed_reloader"`
	ReloaderTimingsMs    map[string]int64 `json:"reloader_timings_ms"`
}

// initial is the status reported before any reload attempt has taken place.
func initial() Status {
	return Status{
		ErrorCategory:     ErrorCategoryNone,
		AppliedReloaders:  []string{},
		ReloaderTimingsMs: map[string]int64{},
	}
}

// Manager tracks the most recent reload outcome in memory and persists it to
// disk so it survives restarts.
type Manager struct {
	logger *slog.Logger
	path   string

	mu     sync.RWMutex
	status Status
}

// NewManager creates a Manager that persists status under storageDir.
// Any previously persisted status is loaded eagerly; a missing or corrupted
// file is not an error and simply results in the initial status.
func NewManager(storageDir string, logger *slog.Logger) *Manager {
	if logger == nil {
		logger = slog.New(slog.DiscardHandler)
	}
	m := &Manager{
		logger: logger,
		path:   filepath.Join(storageDir, persistedStatusFileBaseName),
		status: initial(),
	}
	m.load()
	return m
}

func (m *Manager) load() {
	data, err := os.ReadFile(m.path)
	if err != nil {
		if !errors.Is(err, os.ErrNotExist) {
			m.logger.Warn("Failed to read persisted reload status, starting fresh", "path", m.path, "err", err)
		}
		return
	}

	var s Status
	if err := json.Unmarshal(data, &s); err != nil {
		m.logger.Warn("Failed to parse persisted reload status, starting fresh", "path", m.path, "err", err)
		return
	}
	if s.AppliedReloaders == nil {
		s.AppliedReloaders = []string{}
	}
	if s.ReloaderTimingsMs == nil {
		s.ReloaderTimingsMs = map[string]int64{}
	}
	m.status = s
}

// Get returns the current reload status.
func (m *Manager) Get() Status {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.status
}

// Record stores the given status as the most recent reload outcome and
// persists it to disk. Persistence failures are logged but do not affect the
// in-memory status returned by Get.
func (m *Manager) Record(s Status) {
	m.mu.Lock()
	m.status = s
	m.mu.Unlock()

	data, err := json.MarshalIndent(s, "", "  ")
	if err != nil {
		m.logger.Error("Failed to marshal reload status", "err", err)
		return
	}

	tmpPath := m.path + ".tmp"
	if err := os.WriteFile(tmpPath, data, 0o644); err != nil {
		m.logger.Error("Failed to persist reload status", "path", m.path, "err", err)
		return
	}
	if err := os.Rename(tmpPath, m.path); err != nil {
		m.logger.Error("Failed to persist reload status", "path", m.path, "err", err)
	}
}
