// transactionalReloadState coordinates transactional configuration reloads:
// reloaders are applied in sequence, a single outcome is recorded for the
// whole attempt, and a failed apply triggers a best-effort rollback to the
// last known-good configuration.
type transactionalReloadState struct {
	enabled   bool
	statusMgr *reloadstatus.Manager

	mu             sync.Mutex
	lastGoodConfig *config.Config
}

// Reload performs a configuration reload triggered by an operator (SIGHUP,
// the /-/reload endpoint, or the auto-reload ticker). When transactional mode
// is enabled it records the outcome of the attempt.
func (rs *transactionalReloadState) Reload(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
	if !rs.enabled {
		return reloadConfig(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, rls...)
	}
	return rs.reloadTransactional(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, true, rls...)
}

// InitialLoad performs the initial configuration load at startup. It seeds
// the last known-good configuration used for later rollbacks, but does not
// count as a reload attempt: no status is recorded or persisted.
func (rs *transactionalReloadState) InitialLoad(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), rls ...reloader) error {
	if !rs.enabled {
		return reloadConfig(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, rls...)
	}
	return rs.reloadTransactional(filename, enableExemplarStorage, logger, noStepSubqueryInterval, callback, false, rls...)
}

