func TestManager_InitialStatus(t *testing.T) {
	dir := t.TempDir()
	m := NewManager(dir, nil)

	got := m.Get()
	require.Equal(t, "", got.LastReloadID)
	require.False(t, got.LastReloadSuccessful)
	require.Equal(t, ErrorCategoryNone, got.ErrorCategory)
	require.Empty(t, got.AppliedReloaders)
	require.Empty(t, got.ReloaderTimingsMs)
	require.NoFileExists(t, filepath.Join(dir, persistedStatusFileBaseName))
}

func TestManager_RecordAndPersist(t *testing.T) {
	dir := t.TempDir()
	m := NewManager(dir, nil)

	s := Status{
		LastReloadID:         "2026-07-15T10:00:00Z",
		LastReloadSuccessful: true,
		ErrorCategory:        ErrorCategoryNone,
		AppliedReloaders:     []string{"db_storage", "scrape"},
		ReloaderTimingsMs:    map[string]int64{"db_storage": 3, "scrape": 1},
	}
	m.Record(s)

	require.Equal(t, s, m.Get())
	require.FileExists(t, filepath.Join(dir, persistedStatusFileBaseName))

	// A fresh manager reading the same directory must see the persisted status.
	m2 := NewManager(dir, nil)
	require.Equal(t, s, m2.Get())
}

func TestManager_CorruptedPersistedStateIsIgnored(t *testing.T) {
	dir := t.TempDir()
	require.NoError(t, os.WriteFile(filepath.Join(dir, persistedStatusFileBaseName), []byte("{not json"), 0o644))

	m := NewManager(dir, nil)
	got := m.Get()
	require.Equal(t, "", got.LastReloadID)
	require.Equal(t, ErrorCategoryNone, got.ErrorCategory)
}

func TestManager_MissingStorageDirDoesNotPanic(t *testing.T) {
	dir := filepath.Join(t.TempDir(), "does-not-exist")
	m := NewManager(dir, nil)
	got := m.Get()
	require.Equal(t, ErrorCategoryNone, got.ErrorCategory)

	// Record should log and not panic even though the directory is missing.
	m.Record(Status{ErrorCategory: ErrorCategoryLoadError, AppliedReloaders: []string{}, ReloaderTimingsMs: map[string]int64{}})
}
